#!/usr/bin/env zsh
set -euo pipefail

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m'

log_info()  { echo "${GREEN}[INFO]${NC} \$1" }
log_warn()  { echo "${YELLOW}[WARN]${NC} \$1" >&2 }
log_error() { echo "${RED}[ERROR]${NC} \$1" >&2 }

cleanup() {
    # Cleanup code here
    ${2:true}
}
trap cleanup EXIT

${1:# Main logic}

if [[ ${1:condition} ]]; then
    ${2:# true}
else
    ${3:# false}
fi

if [[ ${1:condition1} ]]; then
    ${2:# branch 1}
elif [[ ${3:condition2} ]]; then
    ${4:# branch 2}
else
    ${5:# default}
fi

select ${1:choice} in ${2:option1 option2 option3 quit}; do
    case \$${1:choice} in
        quit) break ;;
        *) echo "You chose: \$${1:choice}" ;;
    esac
done

_${1:mycommand}() {
    local -a subcmds
    subcmds=(
        'start:Start the service'
        'stop:Stop the service'
        'status:Show status'
    )
    _describe 'command' subcmds
}
compdef _${1:mycommand} ${1:mycommand}

precmd() {
    ${1:# Runs before each prompt display}
}

export ZSH="\$HOME/.oh-my-zsh"
ZSH_THEME="${1:robbyrussell}"
plugins=(
    ${2:git}
    ${3:docker}
    ${4:kubectl}
    ${5:z}
    zsh-autosuggestions
    zsh-syntax-highlighting
)
source \$ZSH/oh-my-zsh.sh

while getopts '${1:hvo:}' opt; do
    case \$opt in
        h) echo "Usage: ..."; return 0 ;;
        v) verbose=1 ;;
        o) output=\$OPTARG ;;
        ?) echo "Invalid option" >&2; return 1 ;;
    esac
done
shift \$((OPTIND - 1))
